package com.example.ppm.controller;
import com.example.ppm.common.R;import com.example.ppm.dto.task.*;import com.example.ppm.dto.history.HistoryResponse;import com.example.ppm.security.CurrentUserContext;import com.example.ppm.service.TaskService;import jakarta.validation.Valid;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.web.bind.annotation.*;import java.time.LocalDateTime;import java.util.List;
@RestController public class TaskController {private final TaskService s;public TaskController(TaskService s){this.s=s;}private Long u(){return CurrentUserContext.require().userId();}
@GetMapping("/api/tasks") public R<List<TaskResponse>> list(@RequestParam(required=false)String keyword,@RequestParam(required=false)Long projectId,@RequestParam(required=false)String type,@RequestParam(required=false)String status,@RequestParam(required=false)@DateTimeFormat(pattern="yyyy-MM-dd HH:mm:ss")LocalDateTime startFrom,@RequestParam(required=false)@DateTimeFormat(pattern="yyyy-MM-dd HH:mm:ss")LocalDateTime startTo){return R.ok(s.list(u(),keyword,projectId,type,status,startFrom,startTo));}
@GetMapping("/api/workbench/tasks") public R<List<TaskResponse>> wb(@RequestParam(required=false)String tab){return R.ok(s.workbench(u(),tab));}
@GetMapping("/api/tasks/{id}/history") public R<List<HistoryResponse>> history(@PathVariable Long id){return R.ok(s.history(u(),id));}
@PostMapping("/api/tasks") public R<TaskResponse> create(@Valid @RequestBody TaskRequest r){return R.ok(s.create(u(),r));}@GetMapping("/api/tasks/{id}")public R<TaskResponse>get(@PathVariable Long id){return R.ok(s.get(u(),id));}@PutMapping("/api/tasks/{id}")public R<TaskResponse>update(@PathVariable Long id,@Valid@RequestBody TaskRequest r){return R.ok(s.update(u(),id,r));}@DeleteMapping("/api/tasks/{id}")public R<Void>del(@PathVariable Long id){s.delete(u(),id);return R.ok();}@PatchMapping("/api/tasks/{id}/status")public R<TaskResponse>status(@PathVariable Long id,@Valid@RequestBody StatusRequest r){return R.ok(s.status(u(),id,r.action()));}}
